body:
Verilator version: `Verilator 5.023 devel rev v5.022-60-g953249aa4`

Tested on Kali Linux `6.5.0-kali3-arm64 #1 SMP Debian 6.5.6-1kali1 (2023-10-09) aarch64 GNU/Linux` and Debian `6.6.16-linuxkit #1 SMP Fri Feb 16 11:54:02 UTC 2024 x86_64 GNU/Linux`

Minimal working example:
```sv
module Testbench;
    typedef struct {
        logic [4:0] id;
    } TestStruct;

    reg [7:0] r_id;

    TestStruct ts;

    initial begin
        r_id = 42;
        ts = '{id: r_id[4:0]};

        $display("ts.id = %d", ts.id);

        $finish;
    end
endmodule
```

Compile command:
```sh
verilator -O0 --binary Testbench.sv && obj_dir/VTestbench
```

`-O0` is required, or the packed assignment is optimized away.

A slightly longer example that does not require `-O0`:

```sv
module Testbench;
    typedef struct {
        logic [4:0] id;
    } TestStruct;

    reg en;

    reg [7:0] r_id;

    TestStruct ts;

    assign ts = '{id: en ? r_id[4:0] : 5'b0};

    initial begin
        en = 1;
        r_id = 42;

        #1;

        $display("ts.id = %d", ts.id);

        $finish;
    end
endmodule
```

Anyone would expect a `ts.id = 10` since it's 5 bits wide. But in the above examples `ts.id = 42` is printed, indicating that values are not properly truncated.

I had a quick look into the generated C++ code and found this skeptical:
```cpp
VL_INLINE_OPT void VTestbench_Testbench___act_sequent__TOP__Testbench__0(VTestbench_Testbench* vlSelf) {
    (void)vlSelf;  // Prevent unused variable warning
    VTestbench__Syms* const __restrict vlSymsp VL_ATTR_UNUSED = vlSelf->vlSymsp;
    VL_DEBUG_IF(VL_DBG_MSGF("+  VTestbench_Testbench___act_sequent__TOP__Testbench__0\n"); );
    // Body
    vlSelf->__PVT__ts = VTestbench_TestStruct__struct__0{
        .__PVT__id = (CData)(((IData)(vlSelf->__PVT__en)
                               ? VL_SEL_IIII(8, (IData)(vlSelf->__PVT__r_id), 0U, 5U)
                               : 0U))};
}
```
In which no truncation is done. Interestingly enough, in the example that does not require `-O0`, if you change `5'b0` to just `0` then the generated code looks good and we have the expected result:
```sv
assign ts = '{id: en ? r_id[4:0] : 0};
```
```cpp
VL_INLINE_OPT void VTestbench___024root___act_sequent__TOP__0(VTestbench___024root* vlSelf) {
    (void)vlSelf;  // Prevent unused variable warning
    VTestbench__Syms* const __restrict vlSymsp VL_ATTR_UNUSED = vlSelf->vlSymsp;
    VL_DEBUG_IF(VL_DBG_MSGF("+    VTestbench___024root___act_sequent__TOP__0\n"); );
    // Body
    vlSelf->Testbench__DOT__ts = VTestbench_Testbench__DOT__TestStruct__struct__0{
        .__PVT__id = (CData)(((IData)(vlSelf->Testbench__DOT__en)
                               ? (0x1fU & (IData)(vlSelf->Testbench__DOT__r_id))
                               : 0U))};
}
```
I'm no SystemVerilog expert, so any kind of comment is appreciated. Thanks!
